    // Create a new pipe to write into, which will get confused
    // about where its data goes due to the previous splice.
    int dummy_pipe[2];
    if (pipe(dummy_pipe) < 0) {
        perror("dummy pipe");
        close(fd);
        close(p[0]);
        if (strstr(data_to_write_str, "\\x") == data_to_write_str) {
            free(data_to_write);
        }
        exit(EXIT_FAILURE);
    }

