        printf("[+] Successfully initiated write. Bytes written: %zd\n", bytes_written);
        if (bytes_written != data_len) {
            fprintf(stderr, "Warning: Not all data was written. Expected %zu, got %zd.\n", data_len, bytes_written);
        }
    }


