    close(fd);
    close(p[0]);
    close(dummy_pipe[0]); // Ensure all FDs are closed
    close(dummy_pipe[1]); // Ensure all FDs are closed

    if (strstr(data_to_write_str, "\\x") == data_to_write_str) {
        free(data_to_write); // Only free if allocated
    }

