    // However, internally, the pipe buffer still points to the mapped file page.
    // The write will then overwrite the read-only file content.
    int p_write_reopen = open("/proc/self/fd/0", O_WRONLY | O_TRUNC); // Dummy FD, not actually writing to this
    if (p_write_reopen < 0) {
